import { Component, OnInit } from '@angular/core';
import { AlertService } from '../../../_services/alert.service';
import {
  NgbModalConfig,
  NgbModal,
  NgbActiveModal,
} from '@ng-bootstrap/ng-bootstrap';
import { Observable } from 'rxjs';

@Component({
  selector: 'Alert',
  templateUrl: './alert.component.html',
  styleUrls: ['./alert.component.css'],
  providers: [NgbModalConfig, NgbModal],
})
export class AlertComponent implements OnInit {
  private showDialog$: Observable<Boolean>;
  constructor(
    public alertService: AlertService,
    config: NgbModalConfig,
    private modalService: NgbModal
  ) {
    this.showDialog$ = alertService.show;
    config.backdrop = 'static';
    config.keyboard = false;
  }
  ngOnInit(): void {
    this.showDialog$.subscribe((res) => {
      if (res) {
        this.modalService.open(AlertComponentModal);
      }
    });
  }
}
@Component({
  selector: 'alert-modal',
  templateUrl: './alert-modal.component.html',
  styleUrls: ['./alert.component.css'],
  providers: [NgbModalConfig, NgbModal],
})
export class AlertComponentModal {
  constructor(
    public alertService: AlertService,
    public activeModal: NgbActiveModal
  ) {}
  close() {
    this.activeModal.close();
    this.alertService.hiddeAlert();
  }
}
