import { Injectable } from '@angular/core';
import { OdooRPCService } from './odoo-rpc.service';
import { Observable } from 'rxjs';
import { AlertService } from '../_services/alert.service';

@Injectable({
  providedIn: 'root',
})
export class RoadmapService {
  constructor(
    public odooRPC: OdooRPCService,
    private alertService: AlertService
  ) {}
  getRoadmaps(leaf = [['state', 'not in', ['done']]]) {
    const transaction$ = new Observable((observer) => {
      this.odooRPC
        .searchRead(
          'stock.delivery.roadmap',
          leaf,
          [
            'display_name',
            'state',
            'preparation_date',
            'name',
            'number',
            'driver_user_id',
            'assistant_ids',
            'vehicle_id',
            'picking_ids',
          ],
          0,
          0
        )
        .then((res) => {
          observer.next(res);
          observer.complete();
        })
        .catch((err) => {
          this.alertService.showAlert(err);
        });
    });
    return transaction$;
  }

  updatePickings(pickings) {
    const transaction$ = new Observable((observer) => {
      this.odooRPC
        .call(
          'stock.picking',
          'write',
          [pickings[0].id, { roadmap_sequence: pickings[0].roadmap_sequence }],
          {}
        )
        .then(() => {
          this.odooRPC
            .call(
              'stock.picking',
              'write',
              [
                pickings[1].id,
                { roadmap_sequence: pickings[1].roadmap_sequence },
              ],
              {}
            )
            .then(() => {
              observer.next(true);
              observer.complete();
            });
        });
    });
    return transaction$;
  }
  getRoadmap(id) {
    const transaction$ = new Observable((observer) => {
      var prlsIds: any = [];

      this.odooRPC
        .read(
          'stock.delivery.roadmap',
          [id],
          [
            'display_name',
            'state',
            'preparation_date',
            'name',
            'number',
            'driver_user_id',
            'assistant_ids',
            'vehicle_id',
            'picking_ids',
          ]
        )
        .then((res) => {
          this.odooRPC
            .searchRead(
              'stock.picking',
              [['id', 'in', res[0]['picking_ids']]],
              [
                'partner_id',
                'name',
                'note',
                'scheduled_date',
                'origin',
                'weight',
                'state',
                'geo_point',
                'roadmap_sequence',
              ],
              0,
              0,
              {},
              'roadmap_sequence asc'
            )
            .then((pickings) => {
              console.log(pickings);
              res[0]['pickings'] = pickings.records;
              var self = this;
              let partners_ids = pickings.records.map((e) => e.partner_id[0]);
              let partner_dict: any = {};
              pickings.records.map(function (p) {
                partner_dict[p['partner_id'][0]] = p;
              });

              this.odooRPC
                .read('res.partner', partners_ids, [
                  'phone',
                  'mobile',
                  'street',
                  'street2',
                  'city',
                  'state_id',
                 ]).then((partners) => {
                  partners.forEach((element, index) => {
                    partner_dict[element.id] = element;
                    pickings.records[index].partner =
                      partner_dict[pickings.records[index].partner_id[0]];
                  });
                  // console.log(res[0]);
                  observer.next(res[0]);
                  observer.complete();
                });

              //console.log('picking', partner_dict);
            });
        })
        .catch((err) => {
          this.alertService.showAlert(err);
        });
    });
    return transaction$;
  }
}
