import { Component, OnInit } from '@angular/core';
import { StockService } from '../../../_services/stock.service';
import { RoadmapService } from '../../../_services/roadmap.service';
import { Router, ActivatedRoute, ParamMap } from '@angular/router';

@Component({
  selector: 'app-roadmap-item',
  templateUrl: './roadmap-item.component.html',
  styleUrls: ['./roadmap-item.component.css'],
})
export class RoadmapItemComponent implements OnInit {
  roadmap: any;
  roadmap_id: number;
  states = {
    done: 'Entregado',
    waiting: 'En espera',
    draft: 'Borrador',
  };
  constructor(
    public stockService: StockService,
    public RoadmapService: RoadmapService,
    private route: ActivatedRoute,
    private router: Router
  ) {}

  ngOnInit(): void {
    this.roadmap_id = Number(this.route['params']['value']['roadmap_id']);
    this.getRoadmap();
  }
  traslateState(state) {}
  getLink(geoPoint) {
    if (geoPoint) {
      const cordinates = JSON.parse(geoPoint).coordinates;
      window.location.href = `geo:${cordinates[0]},${cordinates[1]};u=35`;
      //this.router.navigate(['geomap/' + cordinates]);
    }
  }
  getTel(phone) {
    if (phone) {
      window.location.href = `tel:${phone}`;
    }
  }
  sendWap(phone) {
    if (phone) {
      window.location.href = `whatsapp://send?abid=${phone}`;
    }
  }

  setSecuenceUp(id) {
    const pickUp = this.roadmap.pickings[id];
    const pickDown = this.roadmap.pickings[id - 1];
    if (pickUp && pickDown) {
      if (pickUp.roadmap_sequence !== pickDown.roadmap_sequence) {
        pickUp.roadmap_sequence = pickDown.roadmap_sequence;
        pickDown.roadmap_sequence = pickUp.roadmap_sequence;
      } else {
        pickUp.roadmap_sequence -= 1;
        pickDown.roadmap_sequence += 1;
      }
      this.RoadmapService.updatePickings([pickUp, pickDown]).subscribe(
        (res) => {
          if (res) {
            this.getRoadmap();
          }
        }
      );
    }
  }
  setSecuenceDown(id) {
    const pickUp = this.roadmap.pickings[id];
    const pickDown = this.roadmap.pickings[id + 1];
    if (pickUp && pickDown) {
      if (pickUp.roadmap_sequence !== pickDown.roadmap_sequence) {
        pickUp.roadmap_sequence = pickDown.roadmap_sequence;
        pickDown.roadmap_sequence = pickUp.roadmap_sequence;
      } else {
        pickUp.roadmap_sequence += 1;
        pickDown.roadmap_sequence -= 1;
      }
      this.RoadmapService.updatePickings([pickUp, pickDown]).subscribe(
        (res) => {
          if (res) {
            this.getRoadmap();
          }
        }
      );
    }
  }
  getRoadmap() {
    this.RoadmapService.getRoadmap(
      Number(this.route['params']['value']['roadmap_id'])
    ).subscribe((wh) => {
      this.roadmap = wh;
    });
  }
}
