import { Component, OnInit } from '@angular/core';
import { StockService } from '../../../_services/stock.service';
import { Router, ActivatedRoute, ParamMap } from '@angular/router';

@Component({
  selector: 'app-mov-int',
  templateUrl: './mov-int.component.html',
  styleUrls: ['./mov-int.component.css'],
})
export class MovIntComponent implements OnInit {
  pickings: any = [];
  filters: any = [];
  isCollapsed: boolean = true;
  spinner = true;
  sequence_code: string = 'all';

  inputMethod: String = 'textBus';
  base_leaf: any = [
    ['state', 'in', ['assigned', 'draft', 'partially_available']],
    ['picking_type_id.code', '=', 'internal'],
  ];
  showReadCode: boolean = true;

  constructor(
    private route: ActivatedRoute,
    private router: Router,
    public stockService: StockService
  ) {}

  ngOnInit(): void {
    this.sequence_code = this.route['params']['value']['picking_code'] || 'all';
    this.initFilter();
    this.getPicking();
  }
  removeFilter(index) {
    //const index = this.filters.findIndex((e) => e.name === name);
    this.filters.splice(index, 1);
    this.spinner = true;
    this.getPicking();
  }
  initFilter() {
    let dateExpected = this.makeDateLeaf(
      this.parseDateObject(new Date()),
      undefined
    );

    this.filters.push({
      label: 'movimientos hasta hoy',
      value: { toDate: this.parseDateObject(new Date()) },
      name: 'scheduled_date',
    });
    return dateExpected;
  }
  searchByCode(code) {
    console.log(code);
  }

  getLeaf() {
    let domain = [
      ['state', 'in', ['assigned', 'draft','confirmed', 'partially_available']],
      ['picking_type_id.code', '=', 'internal'],
    ];
    if (this.route['params']['value']['picking_code']) {
      domain.push([
        'picking_type_id.sequence_code',
        '=',
        this.route['params']['value']['picking_code'],
      ]);
    }
    return domain;
  }
  getPicking() {
    let leaf: any = this.getLeaf();
    let dateExpected = this.filters.filter(
      (filter) => filter.name == 'scheduled_date'
    );
    if (dateExpected.length) {
      dateExpected = this.makeDateLeaf(
        dateExpected[0]['value']['fromDate'],
        dateExpected[0]['value']['toDate']
      );
    }

    leaf.push(...dateExpected);
    let pickingOrigin = this.filters.filter(
      (filter) => filter.name == 'origin'
    );
    if (pickingOrigin.length) {
      pickingOrigin.forEach((element) => {
        leaf.push('|');
        leaf.push([element.name, 'like', element.value]);
        leaf.push(['computed_roadmap_id', 'like', element.value]);
      });
    }
    this.stockService.getPicking(leaf).subscribe((res) => {
      this.pickings = res['records'];
      this.spinner = false;
    });
  }

  goPicking(item) {
    console.log(item);
  }
  dateRange(value) {
    const index = this.filters.findIndex((e) => e.name == 'scheduled_date');
    if (index >= 0) {
      this.filters.splice(index, 1);
    }
    if (value.fromDate && value.toDate) {
      const fromDate =
        value.fromDate.day +
        '/' +
        value.fromDate.month +
        '/' +
        value.fromDate.year;
      const toDate =
        value.toDate.day + '/' + value.toDate.month + '/' + value.toDate.year;
      this.filters.push({
        label: fromDate + ' a ' + toDate,
        value: {
          fromDate: this.parseDate(value.fromDate),
          toDate: this.parseDate(value.toDate),
        },
        name: 'scheduled_date',
      });
    } else if (value.fromDate) {
      const fromDate =
        value.fromDate.day +
        '/' +
        value.fromDate.month +
        '/' +
        value.fromDate.year;
      this.filters.push({
        label: fromDate,
        value: { fromDate: this.parseDate(value.fromDate) },
        name: 'scheduled_date',
      });
    }
    this.spinner = true;

    this.getPicking();
  }
  makeDateLeaf(fromDate, toDate) {
    let leaf: any = [];
    if (!toDate) {
      toDate = fromDate;
    } else if (!fromDate) {
      leaf.push(['scheduled_date', '<', toDate + ' 23:59:59']);
    } else {
      leaf.push(['scheduled_date', '>=', fromDate + ' 00:00:00']);
      leaf.push(['scheduled_date', '<', toDate + ' 23:59:59']);
    }

    return leaf;
  }

  private parseDate(date) {
    const zeroPad = (num, places) => String(num).padStart(places, '0');
    return (
      date.year + '-' + zeroPad(date.month, 2) + '-' + zeroPad(date.day, 2)
    );
  }
  private parseDateObject(date) {
    const zeroPad = (num, places) => String(num).padStart(places, '0');

    return (
      date.getFullYear() +
      '-' +
      zeroPad(date.getMonth() + 1, 2) +
      '-' +
      zeroPad(date.getDate(), 2)
    );
  }
  refresh() {
    this.spinner = true;

    this.filters = [];
    this.getPicking();
  }
  addOrigin(object) {
    this.showReadCode = object.showReadCode;
    if (this.showReadCode && object.text) {
      this.filters.push({
        label: 'origen: ' + object.text,
        value: object.text,
        name: 'origin',
      });
      this.spinner = true;
      this.getPicking();
    }
  }
}
